.responsive-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background-color: rgb(33, 37, 41);
  padding: 0 16px;
}
.nav-brand {
  color: rgb(255, 255, 255);
  font-weight: 700;
  font-size: 20px;
  padding: 12px 0;
}
.nav-links {
  display: flex;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 4px;
}
.nav-links a {
  color: rgb(255, 255, 255);
  text-decoration: none;
  padding: 12px 16px;
  display: block;
}
@media (max-width: 768px) {
  .responsive-nav {
    flex-direction: column;
    align-items: stretch;
  }
  .nav-links {
    flex-direction: column;
  }
  .nav-links a {
    padding: 12px 16px;
    border-top: 1px solid rgba(255, 255, 255, 0.1);
  }
}

